import {
    REGISTER_SUCCESS,
    REGISTER_FAIL,
    LOGIN_FAIL,
    LOGIN_SUCCESS,
    LOGOUT,
    SET_MESSAGE,
    ADDSTORYGENRE_SUCCESS, ADDSTORYGENRE_FAIL
} from "./types";
import AuthService from "../services/auth.service";

export const register = (username, email, password) => (dispatch) => {
    return AuthService.register(username, email, password).then(
        (response) => {
            dispatch({
                type: REGISTER_SUCCESS
            })

            dispatch({
                type: SET_MESSAGE,
                payload: response.data.message
            })
            return Promise.resolve();
        },
        (error) => {
            const message = (error.response && error.response.data && error.response.data.message) || error.message || error.toString();

            dispatch({type: REGISTER_FAIL})

            dispatch({type: SET_MESSAGE, payload: message})
            return Promise.reject();
        }
    )
}


export const addStoryGenre = (storyGenreName, description) => (dispatch) => {
    return UserService.addStoryGenre(storyGenreName, description).then(
        (response) => {
            dispatch({
                type: ADD_STORY_GENRE_SUCCESS,
                payload: { storyGenre: response.data },
            });
            return Promise.resolve();
        },
        (error) => {
            dispatch({
                type: ADD_STORY_GENRE_FAIL,
            });
            return Promise.reject();
        }
    );
};


export const login = (email, password) => (dispatch) => {
    return AuthService.login(email, password).then(
        (data) => {
            dispatch({
                type: LOGIN_SUCCESS,
                payload: {user: data}
            })

            return Promise.resolve();
        },
        (error) => {
            const message = (error.response && error.response.data && error.response.data.message) || error.message || error.toString();

            dispatch({type: LOGIN_FAIL})

            dispatch({type: SET_MESSAGE, payload: message})
            return Promise.reject();
        }
    )
}

export const logout = () => (dispatch) => {
    AuthService.logout();
    dispatch({
        type: LOGOUT
    });
}
